# Resolve benchmarks/results.md merge conflicts automatically.
#
# benchmarks/results.md is regenerated by CI on every push to master, so it
# should NEVER need a manual merge. The repo's .gitattributes already maps it to
# 'merge=ours', but that only takes effect once the 'ours' driver is registered
# in this clone's git config -- which this script does. After running once, plain
# 'git pull' auto-resolves results.md forever; you never have to run this again.
#
# What it does:
#   1. Registers the 'ours' merge driver referenced by .gitattributes.
#   2. Finishes any in-progress merge/rebase that is stuck on results.md.
#   3. Otherwise pulls the remote branch (results.md auto-resolves to yours).
#
# Usage: .\scripts\resolve-benchmark-conflicts.ps1 [-RemoteBranch origin/master]
#
# NOTE: keep this file ASCII-only. Windows PowerShell 5.1 reads a BOM-less script
# as the system ANSI codepage, where a stray non-ASCII byte can decode into a
# smart quote that prematurely terminates a string and breaks parsing.

param([string]$RemoteBranch = "origin/master")
$ErrorActionPreference = "Continue"

function Section($m) { Write-Host $m -ForegroundColor Cyan }
function Info($m)    { Write-Host $m -ForegroundColor Gray }
function Ok($m)      { Write-Host $m -ForegroundColor Green }
function Warn($m)    { Write-Host $m -ForegroundColor Yellow }
function Err($m)     { Write-Host $m -ForegroundColor Red }

$RESULTS = "benchmarks/results.md"

$gitDir = (git rev-parse --git-dir 2>$null)
if (-not $gitDir) { Err "Not a git repository."; exit 1 }
$gitDir = $gitDir.Trim()

Section "Tauraro Benchmark Conflict Resolver"
Section "==================================="
Write-Host ""

# 1. Register the merge driver referenced by .gitattributes (idempotent).
#    'true' is the no-op driver: it keeps the current branch's version of the
#    file and exits 0, so a 3-way merge of results.md never reports a conflict.
git config merge.ours.driver "true" | Out-Null
Ok "Merge driver registered - results.md conflicts now auto-resolve on every pull."
Write-Host ""

function Unmerged {
    @(git diff --name-only --diff-filter=U 2>$null | Where-Object { $_ })
}

# Keep OUR results.md and stage it. Returns $true when no OTHER files conflict.
function Resolve-ResultsOnly {
    $u = Unmerged
    if ($u -contains $RESULTS) {
        Info "Resolving $RESULTS (keeping your version)..."
        git checkout --ours -- $RESULTS 2>$null
        git add $RESULTS 2>$null
    }
    return (@(Unmerged | Where-Object { $_ -ne $RESULTS }).Count -eq 0)
}

function Show-OtherConflicts {
    Err ("Conflicts remain in files other than " + $RESULTS + ":")
    Unmerged | Where-Object { $_ -ne $RESULTS } | ForEach-Object { Write-Host "    $_" }
}

# 2a. Finish an in-progress MERGE (e.g. a 'git pull' that stopped on results.md).
if (Test-Path (Join-Path $gitDir "MERGE_HEAD")) {
    Warn "A merge is in progress - completing it..."
    if (Resolve-ResultsOnly) {
        git commit --no-edit | Out-Null
        Ok "Merge completed."
    } else {
        Show-OtherConflicts
        Warn "Resolve those, then run: git commit --no-edit"
        exit 1
    }
    exit 0
}

# 2b. Finish an in-progress REBASE.
if ((Test-Path (Join-Path $gitDir "rebase-merge")) -or (Test-Path (Join-Path $gitDir "rebase-apply"))) {
    Warn "A rebase is in progress - continuing it..."
    if (Resolve-ResultsOnly) {
        git rebase --continue
        Ok "Rebase continued."
    } else {
        Show-OtherConflicts
        Warn "Resolve those, then run: git rebase --continue"
        exit 1
    }
    exit 0
}

# 3. Clean start: stash local edits, pull (results.md auto-resolves), restore.
$dirty   = @(git status --porcelain 2>$null | Where-Object { $_ }).Count -gt 0
$stashed = $false
if ($dirty) {
    Info "Stashing your local changes..."
    git stash push -u -m "resolve-benchmark-conflicts auto-stash" | Out-Null
    $stashed = $true
}

$remote = ($RemoteBranch -split '/', 2)[0]
Info "Fetching $remote..."
git fetch $remote 2>&1 | Out-Null

Info "Merging $RemoteBranch (results.md auto-resolves to yours)..."
git merge --no-edit $RemoteBranch
if ($LASTEXITCODE -ne 0) {
    if (Resolve-ResultsOnly) {
        git commit --no-edit | Out-Null
        Ok "Merged; results.md kept yours."
    } else {
        Show-OtherConflicts
        if ($stashed) { Warn "Your changes are stashed - after resolving, run: git stash pop" }
        exit 1
    }
}

if ($stashed) {
    Info "Restoring your stashed changes..."
    git stash pop
}

$branch = (git rev-parse --abbrev-ref HEAD 2>$null).Trim()
Write-Host ""
Ok "Done. Push with: git push $remote $branch"
